def _run(cmd, cwd):
    return subprocess.run(cmd, cwd=str(cwd), capture_output=True, text=True, timeout=120)


def test_AC_04():
    """
    GIVEN: scripts/blast-radius-tool.py is read AND two deterministic fixtures are executed
    WHEN:  Fixture A: temp git repo with one tracked-modified file + one untracked-non-ignored file; invoke `blast-radius-tool.py --git-diff --base HEAD --output /tmp/br-fixture-a.json --task-id fixture-a` from that repo. Fixture B: temp tree where one source file is textually referenced from >50 sibling files; invoke `blast-radius-tool.py --files <fanout-source> --output /tmp/br-fixture-b.json --task-id fixture-b`
    THEN:  Fixture A analyzed_files contains both tracked-modified AND untracked-non-ignored, each exactly once; source git_diff_files body contains 'ls-files' + '--others' + '--exclude-standard'; source defines module-level MAX_EDGES_PER_SOURCE_FILE = 50; Fixture B edges where from == fanout-source count is <= 50 AND omitted_edges_count > 0 AND omitted_edges_count == actual_input_reference_count - 50; Fixture A output top-level includes omitted_edges_count as integer; dedup is by (from, to, edge_type) 3-tuple
    """
    assert TOOL.exists(), f"{TOOL} not found"
    src = TOOL.read_text(encoding="utf-8")

    # Source-level tokens
    for tok in ["ls-files", "--others", "--exclude-standard", "MAX_EDGES_PER_SOURCE_FILE = 50"]:
        assert tok in src, f"scripts/blast-radius-tool.py missing required token {tok!r}"

    # git_diff_files body must contain the three flags
    tree = ast.parse(src)
    found_fn = None
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef) and node.name == "git_diff_files":
            found_fn = node
            break
    assert found_fn is not None, "git_diff_files function not defined"
    fn_src = ast.get_source_segment(src, found_fn) or ""
    for tok in ["ls-files", "--others", "--exclude-standard"]:
        assert tok in fn_src, f"git_diff_files body missing token {tok!r}"

    # Fixture A — untracked file detection
    with tempfile.TemporaryDirectory() as td_a:
        repo_a = Path(td_a) / "tempdir"
        repo_a.mkdir()
        _run(["git", "init", "-q"], cwd=repo_a)
        _run(["git", "config", "user.email", "t@t.t"], cwd=repo_a)
        _run(["git", "config", "user.name", "t"], cwd=repo_a)
        (repo_a / "tracked.txt").write_text("a\n")
        _run(["git", "add", "tracked.txt"], cwd=repo_a)
        _run(["git", "commit", "-q", "-m", "init"], cwd=repo_a)
        (repo_a / "tracked.txt").write_text("a\nb\n")
        (repo_a / "untracked.txt").write_text("c\n")

        out_a = Path(td_a) / "br-fixture-a.json"
        r = _run(
            ["python3", str(TOOL), "--git-diff", "--base", "HEAD",
             "--output", str(out_a), "--task-id", "fixture-a"],
            cwd=repo_a,
        )
        assert out_a.exists(), (
            f"Fixture A output not produced; rc={r.returncode}\n"
            f"stdout:{r.stdout}\nstderr:{r.stderr}"
        )
        rep_a = json.loads(out_a.read_text(encoding="utf-8"))

        analyzed = rep_a.get("analyzed_files", [])
        assert analyzed.count("tracked.txt") == 1, (
            f"tracked.txt expected exactly once; analyzed_files={analyzed}"
        )
        assert analyzed.count("untracked.txt") == 1, (
            f"untracked.txt expected exactly once; analyzed_files={analyzed}"
        )
        assert "omitted_edges_count" in rep_a, "top-level omitted_edges_count missing"
        assert isinstance(rep_a["omitted_edges_count"], int), (
            f"omitted_edges_count must be int; got {type(rep_a['omitted_edges_count']).__name__}"
        )

        # Dedup check
        edges = rep_a.get("edges", [])
        triples = [(e.get("from"), e.get("to"), e.get("edge_type")) for e in edges]
        assert len(triples) == len(set(triples)), (
            "edges contain duplicate (from,to,edge_type) triples"
        )

    # Fixture B — high-fanout cap
    with tempfile.TemporaryDirectory() as td_b:
        fan = Path(td_b) / "tempfanout"
        fan.mkdir()
        (fan / "util.py").write_text("def util(): pass\n")
        for i in range(1, 61):
            (fan / f"caller_{i}.py").write_text("from util import util\n")

        out_b = Path(td_b) / "br-fixture-b.json"
        r = _run(
            ["python3", str(TOOL), "--files", "util.py",
             "--output", str(out_b), "--task-id", "fixture-b"],
            cwd=fan,
        )
        assert out_b.exists(), (
            f"Fixture B output not produced; rc={r.returncode}\n"
            f"stdout:{r.stdout}\nstderr:{r.stderr}"
        )
        rep_b = json.loads(out_b.read_text(encoding="utf-8"))

        edges_b = rep_b.get("edges", [])
        from_count = sum(1 for e in edges_b if e.get("from") == "util.py")
        assert from_count <= 50, (
            f"Fanout cap violated: {from_count} edges with from=util.py exceeds 50"
        )
        omitted = rep_b.get("omitted_edges_count", 0)
        assert isinstance(omitted, int) and omitted > 0, (
            f"omitted_edges_count expected positive int; got {omitted!r}"
        )
        # 60 input refs - 50 emitted = at least 10 omitted
        assert omitted + from_count >= 60, (
            f"omitted_edges_count ({omitted}) + emitted ({from_count}) "
            f"should be >= 60 total input references"
        )
